            if len(cat) >= 3 and len(cat) <= 50:
                lower_cat = cat.lower()
                # Skip common words and location indicators
                if lower_cat not in ['this', 'offers', 'provides', 'including', 'located', 'located at']:
                    if not any(loc in lower_cat for loc in ['avenue', 'street', 'road', 'boulevard', 'drive', 'suite', 'floor', 'highway']):
                        categories.append(cat)
                        found_categories = True

